// With bookmarks
const [bookmarks, setBookmarks] = useState<string[]>([])

<Blog
  bookmarkedIds={bookmarks}
  onBookmark={(post) => {
    setBookmarks(prev =>
      prev.includes(post.id)
        ? prev.filter(id => id !== post.id)
        : [...prev, post.id]
    )
  }}
/>

// Compact variant for sidebars or lists
<BlogCard
  post={post}
  variant="compact"
  onPress={handlePostPress}
/>

// With bookmarks and filters
<BlogList
  initialCategory="tutorials"
  bookmarkedIds={bookmarks}
  onBookmark={(post) => toggleBookmark(post.id)}
  onFilterPress={() => setShowFilters(true)}
/>

// With pre-fetched post data and bookmarks
<BlogPostDetail
  post={selectedPost}
  onBookmark={(post) => toggleBookmark(post.id)}
  isBookmarked={bookmarks.includes(selectedPost.id)}
/>

// Outline and ghost variants
<Button variant="outline" onPress={handleCancel}>Cancel</Button>
<Button variant="ghost" onPress={handleSkip}>Skip</Button>

// With custom accent color
<ChatScreen
  accentColor="#6366F1"
  placeholder="Type your question..."
  onSupportPress={() => setShowSupport(true)}
/>

// With custom project ID
<FormRenderer
  formId="feedback-form"
  projectId="custom-project-id"
  onSuccess={() => setShowThankYou(true)}
/>

import { HelpArticleCard } from '@appgram/react-native'

function ArticleList({ articles }) {
  return (
    <View>
      {articles.map(article => (
        <HelpArticleCard
          key={article.id}
          article={article}
          onPress={(a) => navigation.navigate('HelpArticle', { article: a })}
        />
      ))}
    </View>
  )
}

import { HelpArticleDetail } from '@appgram/react-native'

function HelpArticleScreen({ route }) {
  const { article } = route.params

  return (
    <HelpArticleDetail
      article={article}
      style={{ flex: 1 }}
      contentContainerStyle={{ paddingHorizontal: 16 }}
    />
  )
}

// With grid layout
<HelpCenter
  numColumns={2}
  emptyText="No help articles available yet"
/>

import { HelpFlowCard } from '@appgram/react-native'

function HelpFlowList({ flows }) {
  return (
    <View>
      {flows.map(flow => (
        <HelpFlowCard
          key={flow.id}
          flow={flow}
          onPress={(f) => navigation.navigate('HelpFlow', { flow: f })}
        />
      ))}
    </View>
  )
}

import { HelpFlowDetail } from '@appgram/react-native'

function HelpFlowScreen({ route }) {
  const { flow } = route.params

  return (
    <HelpFlowDetail
      flow={flow}
      onArticlePress={(article) => {
        navigation.navigate('HelpArticle', { article })
      }}
      emptyText="No articles available"
    />
  )
}

// With validation error
<Input
  label="Password"
  value={password}
  onChangeText={setPassword}
  secureTextEntry
  error={password.length < 8 ? 'Password must be at least 8 characters' : undefined}
/>

import { ReleaseList } from '@appgram/react-native'

function ChangelogScreen() {
  return (
    <ReleaseList
      title="Changelog"
      description="See what's new"
      limit={20}
      onReleasePress={(release) => {
        navigation.navigate('ReleaseDetail', { slug: release.slug })
      }}
    />
  )
}

// With custom form
<SubmitWishSheet
  visible={visible}
  onClose={() => setVisible(false)}
  customFormId="feature-request-form"
  onSuccess={(wish) => refetchWishes()}
  onError={(error) => Alert.alert('Error', error)}
/>

import { SurveyForm } from '@appgram/react-native'

function SurveyScreen() {
  return (
    <SurveyForm
      slug="customer-satisfaction"
      onSuccess={() => {
        Alert.alert('Thank you!', 'Your feedback has been recorded.')
        navigation.goBack()
      }}
      onError={(error) => Alert.alert('Error', error)}
    />
  )
}

// In a FlatList
<FlatList
  data={wishes}
  renderItem={({ item }) => (
    <WishCard wish={item} onPress={handlePress} />
  )}
  keyExtractor={(item) => item.id}
/>

import { WishDetailModal } from '@appgram/react-native'

function WishListScreen() {
  const [selectedWish, setSelectedWish] = useState<Wish | null>(null)

  return (
    <>
      <FlatList
        data={wishes}
        renderItem={({ item }) => (
          <WishCard wish={item} onPress={() => setSelectedWish(item)} />
        )}
      />
      <WishDetailModal
        wish={selectedWish}
        visible={!!selectedWish}
        onClose={() => setSelectedWish(null)}
        onVote={(wishId) => console.log('Voted:', wishId)}
      />
    </>
  )
}

// With filters and auto-refresh
<WishList
  filters={{ status: 'pending', sort_by: 'votes' }}
  refreshInterval={30000}
  showSubmitButton={false}
  emptyText="No pending requests"
/>

// Simple slug-based routing
onArticlePress={(slug) => navigation.navigate('HelpArticle', { slug })}

// Using flow context for nested routes
onArticlePress={(slug, source) => {
  if (source.flow_slug) {
    navigation.navigate('HelpArticle', { flowSlug: source.flow_slug, slug })
  } else {
    navigation.navigate('HelpArticle', { slug })
  }
}}

description.summary:
In the absence of auto property, none is much like CSS's none value. box-none is as if you had applied the CSS class:

.box-none {
  pointer-events: none;
}
.box-none * {
  pointer-events: all;
}

box-only is the equivalent of

.box-only {
  pointer-events: all;
}
.box-only * {
  pointer-events: none;
}

But since pointerEvents does not affect layout/appearance, and we are already deviating from the spec by adding additional modes,
we opt to not include pointerEvents on style. On some platforms, we would need to implement it as a className anyways. Using style or not is an implementation detail of the platform.
